# ── DATABASE ──────────────────────────────────────────────────────
DB = "healnet_auth.db"

def db():
    c = sqlite3.connect(DB, check_same_thread=False)
    c.row_factory = sqlite3.Row
    return c

def init_db():
    con = db()
    con.executescript("""
    CREATE TABLE IF NOT EXISTS organisations(
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        name TEXT NOT NULL, username TEXT UNIQUE NOT NULL,
        password TEXT NOT NULL, org_code TEXT UNIQUE NOT NULL,
        email TEXT);
    CREATE TABLE IF NOT EXISTS staff(
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        org_id INTEGER, name TEXT, username TEXT,
        password TEXT, role TEXT, phone TEXT, staff_id TEXT,
        email TEXT, UNIQUE(username,org_id));
    CREATE TABLE IF NOT EXISTS org_patients(
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        org_id INTEGER, name TEXT, username TEXT,
        password TEXT, age INTEGER, gender TEXT,
        contact TEXT, patient_id TEXT, email TEXT, UNIQUE(username,org_id));
    CREATE TABLE IF NOT EXISTS solo_users(
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        name TEXT, email TEXT UNIQUE, username TEXT UNIQUE,
        password TEXT, gender TEXT, dob TEXT,
        blood TEXT, contact TEXT, healnet_id TEXT UNIQUE);
    """)
    # Add email column if missing (for existing DBs)
    for tbl in ["organisations","staff","org_patients"]:
        try: con.execute(f"ALTER TABLE {tbl} ADD COLUMN email TEXT")
        except: pass
    con.commit(); con.close()

init_db()
def hp(p): return hashlib.sha256(p.encode()).hexdigest()
def gen_code(): return "HN-" + "".join(random.choices(string.ascii_uppercase+string.digits,k=5))
def org_by_code(code):
    con=db(); r=con.execute("SELECT * FROM organisations WHERE org_code=?",(code.upper().strip(),)).fetchone(); con.close()
    return dict(r) if r else None

# ── SESSION ───────────────────────────────────────────────────────
def S(k,v):
    if k not in st.session_state: st.session_state[k]=v
S("screen","entry"); S("session",None); S("msg",None); S("msg_type","error")
S("otp_code",None); S("otp_target",None); S("otp_user_type",None); S("otp_expiry",None); S("reset_username",None)
def go(s): st.session_state.screen=s; st.session_state.msg=None
def alert(m,t="error"): st.session_state.msg=m; st.session_state.msg_type=t
def do_login(kind, user=None, org=None):

    # Create session
    st.session_state.session = {
        "kind": kind,
        "user": user,
        "org": org
    }

    # Clear message
    st.session_state.msg = None

    # OPEN DASHBOARD PAGE (app.py inside pages folder)
    st.switch_page("pages/app.py")
def show_msg():
    if st.session_state.msg:
        t=st.session_state.msg_type
        if t=="success": st.success(st.session_state.msg)
        elif t=="info":  st.info(st.session_state.msg)
        else:            st.error(st.session_state.msg)

