def screen_entry():
    logo(); card_open()
    st.markdown('<div class="hn-card-title" style="font-size:22px;color:#ffffff;">Welcome to HealNet</div>', unsafe_allow_html=True)
    st.markdown('<div class="hn-card-sub" style="font-size:15px;color:#ffffff;">Select your account type to continue.</div>', unsafe_allow_html=True)
    for key,title,sub in [
        ("org",       "Organisation",        "Hospital / Clinic  ·  Manage staff and patients"),
        ("staff",     "Doctor / Staff",       "Needs Org Code  ·  You work at a registered facility"),
        ("orgpatient","Patient at a Hospital","Needs Org Code  ·  Your hospital gave you a code"),
        ("solo",      "Individual / Personal","No code needed  ·  Sign up free"),
    ]:
        if st.button(f"{title}\n{sub}", key=f"opt_{key}"): go(key); st.rerun()
    st.markdown('''<div class="note-box"><strong style="color:#475569;">Not sure?</strong> Hospital gave you a code → <em>Patient at a Hospital</em>. No code → <em>Individual / Personal</em>.</div>''', unsafe_allow_html=True)
