# OTP HELPERS
# ════════════════════════════════════════════════════════════════
import time, random

def generate_otp():
    return str(random.randint(100000, 999999))

def get_user_email(user_type, username):
    """Return the registered email for any user type."""
    con = db()
    tables = {
        "org":        ("organisations", "username"),
        "staff":      ("staff",         "username"),
        "orgpatient": ("org_patients",  "username"),
        "solo":       ("solo_users",    "username"),
    }
    tbl, col = tables[user_type]
    row = con.execute(f"SELECT email FROM {tbl} WHERE {col}=?", (username,)).fetchone()
    con.close()
    return row["email"] if row and row["email"] else None

def mask_email(email):
    """Show j***@gmail.com for privacy."""
    if not email or "@" not in email: return "***"
    u, d = email.split("@", 1)
    return u[0] + "***@" + d

def send_otp(user_type, username):
    otp   = generate_otp()
    email = get_user_email(user_type, username)
    st.session_state.otp_code      = otp
    st.session_state.otp_target    = username
    st.session_state.otp_email     = email
    st.session_state.otp_user_type = user_type
    st.session_state.otp_expiry    = time.time() + 300
    st.session_state.reset_username = username

    if email:
        ok, err = send_email_otp(email, otp)
        if ok:
            alert(f"✅ OTP sent to {mask_email(email)}. Check your inbox and spam folder.", "info")
        elif err == "SMTP_NOT_CONFIGURED":
            alert(f"⚙️ Email not configured yet. Your Demo OTP is: {otp}", "info")
        elif err == "AUTH_ERROR":
            alert(f"❌ Gmail login failed — check your App Password. Demo OTP: {otp}", "error")
        else:
            alert(f"❌ Email send failed. Demo OTP: {otp} (Error: {err})", "error")
    else:
        alert(f"⚠️ No email found for this account. Demo OTP: {otp}", "info")

def otp_valid(entered):
    if not st.session_state.otp_code: return False, "No OTP generated."
    if time.time() > st.session_state.otp_expiry: return False, "OTP expired. Please request a new one."
    if entered.strip() != st.session_state.otp_code: return False, "Incorrect OTP. Please try again."
    return True, "OK"

def lookup_user_for_reset(user_type, username):
    con = db()
    tables = {
        "org":        ("organisations", "username"),
        "staff":      ("staff",         "username"),
        "orgpatient": ("org_patients",  "username"),
        "solo":       ("solo_users",    "username"),
    }
    tbl, col = tables[user_type]
    row = con.execute(f"SELECT * FROM {tbl} WHERE {col}=?", (username,)).fetchone()
    con.close()
    return dict(row) if row else None

def reset_password_in_db(user_type, username, new_pass):
    tables = {
        "org":        "organisations",
        "staff":      "staff",
        "orgpatient": "org_patients",
        "solo":       "solo_users",
    }
    tbl = tables[user_type]
    con = db()
    con.execute(f"UPDATE {tbl} SET password=? WHERE username=?", (hp(new_pass), username))
    con.commit(); con.close()


