# SCREEN: FORGOT PASSWORD — Step 1: Enter username + select type
# ════════════════════════════════════════════════════════════════
def screen_forgot():
    card_logo(); card_open()
    st.markdown('<div class="card-title" style="font-size:22px;color:#fff;font-weight:700;margin-bottom:4px;">🔑 Forgot Password</div>', unsafe_allow_html=True)
    st.markdown('<div class="card-sub" style="font-size:15px;color:rgba(255,255,255,0.85);margin-bottom:20px;">Enter your username and account type. We\'ll send an OTP to your registered email.</div>', unsafe_allow_html=True)
    show_msg()
    user_type = st.selectbox("Account Type", ["org","staff","orgpatient","solo"],
        format_func=lambda x: {"org":"🏥 Organisation","staff":"👨‍⚕️ Doctor / Staff","orgpatient":"🏨 Hospital Patient","solo":"👤 Individual / Personal"}[x],
        key="fp_type")
    username = st.text_input("Username", placeholder="Enter your registered username", key="fp_user")
    st.markdown("<br>", unsafe_allow_html=True)
    col1, col2 = st.columns(2)
    with col1:
        if st.button("← Back to Login", key="fp_back", type="secondary"):
            go("entry"); st.rerun()
    with col2:
        if st.button("Send OTP →", key="fp_send", type="primary"):
            if not username:
                alert("⚠️ Please enter your username."); st.rerun()
            else:
                row = lookup_user_for_reset(user_type, username)
                if not row:
                    alert("⚠️ No account found with that username."); st.rerun()
                else:
                    email = row.get("email","")
                    if not email:
                        alert("⚠️ No email on record for this account. Please contact support."); st.rerun()
                    else:
                        send_otp(user_type, username)
                        go("otp_verify"); st.rerun()
    card_close()


