# SCREEN: RESET PASSWORD — Step 3: Set new password
# ════════════════════════════════════════════════════════════════
def screen_reset_password():
    card_logo(); card_open()
    st.markdown('<div class="card-title" style="font-size:22px;color:#fff;font-weight:700;margin-bottom:4px;">🔒 Reset Password</div>', unsafe_allow_html=True)
    st.markdown('<div class="card-sub" style="font-size:15px;color:rgba(255,255,255,0.85);margin-bottom:20px;">OTP verified! Choose a strong new password.</div>', unsafe_allow_html=True)
    show_msg()
    new_pass  = st.text_input("New Password", type="password", placeholder="Min. 6 characters", key="rp_new")
    conf_pass = st.text_input("Confirm New Password", type="password", placeholder="Repeat new password", key="rp_conf")
    st.markdown("<br>", unsafe_allow_html=True)
    if st.button("Reset Password ✓", key="rp_btn", type="primary"):
        if not new_pass:         alert("⚠️ Please enter a new password."); st.rerun()
        elif not conf_pass:      alert("⚠️ Please confirm your new password."); st.rerun()
        elif len(new_pass) < 6:  alert("⚠️ Password must be at least 6 characters."); st.rerun()
        elif new_pass != conf_pass: alert("⚠️ Passwords do not match."); st.rerun()
        else:
            reset_password_in_db(st.session_state.otp_user_type, st.session_state.reset_username, new_pass)
            st.session_state.otp_code = None
            st.session_state.otp_target = None
            st.session_state.otp_user_type = None
            st.session_state.otp_email = None
            st.session_state.reset_username = None
            alert("✅ Password reset successfully! Please sign in with your new password.", "success")
            go("entry"); st.rerun()
    card_close()


